mapper.update:
	UPDATE EVA_POOL_M
 	SET
 	DI 	= #{di}
 	, PRIV_YN 	= 'Y'	 	
	, PRIV_DTTM = sysdate
	, NAME   = #{name}
	, GENDER  = #{gender}		
	, BIRTHDAY  = #{birthDay}
	, INPT_ID = #{sname}		
	, INPT_DT = sysdate		
	, LAST_CHG_DT = sysdate
 	WHERE 
 		TEL_HP   = #{telHp}
 		AND NAME = #{name}

	UPDATE EVA_POOL_DEGREE
 	SET
 		DI 	= #{di}
 		, INPT_ID = #{sname}		
	    , INPT_DT = sysdate			 	
 	WHERE 
 		USR_ID = #{usrId}

	UPDATE EVA_POOL_FULLTIME_TEACHER
 	SET
 		DI 	= #{di}	
 		, INPT_ID = #{sname}		
	    , INPT_DT = sysdate		 	
 	WHERE 
 		USR_ID = #{usrId}

	UPDATE EVA_POOL_EVA_EXP
 	SET
 		DI 	= #{di}
 		, INPT_ID = #{sname}		
	    , INPT_DT = sysdate			 	
 	WHERE 
 		USR_ID = #{usrId}
